      "expected_output": "canonical={\"regex\":{\"$regularExpression\":{\"pattern\":\"^abc\",\"options\":\"im\"}},\"timestamp\":{\"$timestamp\":{\"t\":10,\"i\":2}}}\n"
    },
    {
      "input": {
        "task": "regex_timestamp",
        "pattern": "a.*z",
        "options": "",
        "time": 0,
        "increment": 0
