      "expected_output": "canonical={\"regex\":{\"$regularExpression\":{\"pattern\":\"a.*z\",\"options\":\"\"}},\"timestamp\":{\"$timestamp\":{\"t\":0,\"i\":0}}}\n"
    }
  ]
}
